```class Solution {
    public int[] popcountDepth(long[] nums, long[][] queries) {
        int[] result = new int[queries.length];
        int[] count = new int[10];
        int[] depth = new int[10];

        for (int i = 0; i < nums.length; i++) {
            count[nums[i]]++;
        }

        for (int[] query : queries) {
            int k = query[2];
            int l = query[0];
            int r = query[1];
            int idx = query[3];

            int depth = 0;
            for (int i = l; i <= r; i++) {
                depth += count[nums[i] * Math.pow(2, depth);
            }
            result[query.length() - 1] = depth;
        }

        return result;
    }
}
